oxy_webhelp_navlinks = {"tocId-d27243e2271":{"topics":[{"title":"Rubrik cluster deployment","shortdesc":"<p class=\"shortdesc\">Deploying a Rubrik cluster running on Rubrik appliance nodes involves installing the         CDM software on the nodes and setting up that software for your environment.<\/p>","href":"install\/rsc_cluster_deployment.html","attributes":{"data-id":"rsc_cluster_deployment"},"menu":{"hasChildren":false},"tocID":"rsc_cluster_deployment-d27243e2712","next":"rsc_cluster_deployment-d27243e2712"},{"title":"Cluster registration","shortdesc":"<p class=\"shortdesc\">Rubrik offers two modes for registering clusters with <span class=\"ph\">Rubrik Security Cloud<\/span>,         online and offline.<\/p>","href":"install\/rsc_cluster_registration.html","attributes":{"data-id":"rsc_cluster_registration"},"menu":{"hasChildren":false},"tocID":"rsc_cluster_registration-d27243e2859","next":"rsc_cluster_registration-d27243e2859"},{"title":"Rubrik MFA with TOTP","shortdesc":"<p class=\"shortdesc\">The Rubrik two-step verification feature uses time-based one-time passwords in         addition to the user login credentials to enforce multi-factor authentication on user         accounts.<\/p>","href":"saas\/common\/rsc_rmfa_totp.html","attributes":{"data-id":"rsc_rmfa_totp"},"menu":{"hasChildren":false},"tocID":"rsc_rmfa_totp-d27243e2923","next":"rsc_rmfa_totp-d27243e2923"},{"title":"CLI administrator role","shortdesc":"<p class=\"shortdesc\">As a CLI administrator, a Rubrik cluster user can connect to nodes in Rubrik clusters         through the CLI Secure Shell (SSH) protocol.<\/p>","href":"cdm_old\/cli_administrator_role.html","attributes":{"data-id":"cli_administrator_role"},"menu":{"hasChildren":false},"tocID":"cli_administrator_role-d27243e2956","next":"cli_administrator_role-d27243e2956"},{"title":"Jumbo frame support","shortdesc":"<p class=\"shortdesc\">For Rubrik CDM versions 9.4 and later, you can set the value for the maximum         transmission unit to a maximum value of 10000, instead of the default value of 1500. This         larger unit size is called jumbo frames.<\/p>","href":"cdm_old\/jumbo_frame_support.html","attributes":{"data-id":"jumbo_frame_support"},"menu":{"hasChildren":false},"tocID":"jumbo_frame_support-d27243e3000","next":"jumbo_frame_support-d27243e3000"},{"title":"System shutdown","shortdesc":"<p class=\"shortdesc\">A system shutdown can be done from the Rubrik CLI.<\/p>","href":"install\/system_shutdown.html","attributes":{"data-id":"system_shutdown"},"menu":{"hasChildren":false},"tocID":"system_shutdown-d27243e3044","next":"system_shutdown-d27243e3044"},{"title":"Rubrik CDM software upgrade","shortdesc":"<p class=\"shortdesc\">To take advantage of the latest features and improvements, you can upgrade your         Rubrik CDM software running on your Rubrik clusters to the latest version.<\/p>","href":"saas\/rbk_cdm_software_upgrade.html","attributes":{"data-id":"rbk_cdm_software_upgrade"},"menu":{"hasChildren":false},"tocID":"rbk_cdm_software_upgrade-d27243e3077","next":"rbk_cdm_software_upgrade-d27243e3077"},{"title":"Polaris to <span class=\"ph\">RSC<\/span> upgrade","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> provides a unified user interface to manage all your Rubrik         tasks.<\/p>","href":"install\/upgrade_to_rubrik_security_cloud.html","attributes":{"data-id":"upgrade_to_rsc"},"menu":{"hasChildren":false},"tocID":"upgrade_to_rsc-d27243e3454","next":"upgrade_to_rsc-d27243e3454"}]}};